const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const now = Date.now();
const nowISO = new Date(now).toISOString();

const cfg = global.get('config.device_monitoring')?.appliances?.dishwasher?.attention || {
    vent_zone_threshold: -5,
    unload_zone_threshold: -80,
    venting_timeout_s: 900,
    guest_duration_s: 360,
    likely_empty_timeout_h: 2,
    nag_first_h: 1,
    nag_repeat_h: 2,
    notify_on_likely_empty_timeout: false
};

let opState        = flow.get('operational_state') || 'IDLE';
let contentState   = flow.get('content_state')     || 'DIRTY';
let attentionState = flow.get('attention_state')   || 'NONE';

const prevContent   = contentState;
const prevAttention = attentionState;

let attentionTrigger    = null;
let contentTrigger      = null;
let notificationPayload = null;
const type = msg.event_type;

if (type === 'cycle_started') {
    opState        = 'RUNNING';
    contentState   = 'DIRTY';
    attentionState = 'NONE';
    flow.set('unload_zone_entry_time', null);
    flow.set('vent_zone_entry_time', null);
    flow.set('likely_empty_entry_time', null);

} else if (type === 'cycle_finished') {
    opState = 'IDLE';
    if (contentState === 'DIRTY') {
        contentState     = 'CLEAN';
        attentionState   = 'UNATTENDED';
        attentionTrigger = 'cycle_finished';
        flow.set('cycle_finished_at', nowISO);
        flow.set('cycle_finished_ms', now);
        flow.set('vented', false);
        flow.set('vented_at', null);
        flow.set('nag_count', 0);
        flow.set('last_nag_at', null);
        flow.set('likely_empty_entry_time', null);
        notificationPayload = { type: 'cycle_finished' };
    }

} else if (opState === 'IDLE') {

    if (type === 'button') {
        if (['UNATTENDED', 'VENTING', 'LIKELY_EMPTY'].includes(attentionState)) {
            attentionState   = 'NONE';
            attentionTrigger = 'button';
            notificationPayload = { type: 'button_confirmed' };
            flow.set('vent_zone_entry_time', null);
            flow.set('unload_zone_entry_time', null);
            flow.set('likely_empty_entry_time', null);
        }

    } else if (type === 'tilt' && attentionState !== 'NONE') {
        const { angle_x, zone } = msg.tilt;
        flow.set('last_angle_x', angle_x);
        flow.set('last_door_event_at', nowISO);

        if (attentionState === 'UNATTENDED') {
            if (zone === 'closed_vent') {
                attentionState   = 'VENTING';
                attentionTrigger = 'vent_opened';
                flow.set('vent_zone_entry_time', now);
                flow.set('vented', true);
                flow.set('vented_at', nowISO);
                flow.set('unload_zone_entry_time', null);
            } else if (zone === 'unload') {
                if (!flow.get('unload_zone_entry_time')) {
                    flow.set('unload_zone_entry_time', now);
                }
            } else {
                flow.set('unload_zone_entry_time', null);
            }
        } else if (attentionState === 'VENTING') {
            if (zone !== 'closed_vent') {
                attentionState   = 'UNATTENDED';
                attentionTrigger = 'vent_closed';
                flow.set('vent_zone_entry_time', null);
                notificationPayload = { type: 'venting_to_unattended' };
            }
        }

    } else if (type === 'tick') {

        if (attentionState === 'VENTING') {
            const ventEntry = flow.get('vent_zone_entry_time');
            if (ventEntry && (now - ventEntry) >= cfg.venting_timeout_s * 1000) {
                attentionState   = 'UNATTENDED';
                attentionTrigger = 'vent_timeout';
                flow.set('vent_zone_entry_time', null);
                notificationPayload = { type: 'venting_to_unattended' };
            }

        } else if (attentionState === 'UNATTENDED' || attentionState === 'LIKELY_EMPTY') {
            const unloadEntry = flow.get('unload_zone_entry_time');
            if (unloadEntry && (now - unloadEntry) >= cfg.guest_duration_s * 1000) {
                attentionState   = 'LIKELY_EMPTY';
                attentionTrigger = 'guest_heuristic';
                flow.set('unload_zone_entry_time', null);
                flow.set('likely_empty_entry_time', now);
                notificationPayload = { type: 'likely_empty' };
            } else {
                const cycleMs     = flow.get('cycle_finished_ms') || now;
                const lastNag     = flow.get('last_nag_at');
                const nagCount    = flow.get('nag_count') || 0;
                const firstNagMs  = cfg.nag_first_h  * 3600000;
                const repeatNagMs = cfg.nag_repeat_h * 3600000;
                const nagDue = nagCount === 0
                    ? (now - cycleMs) >= firstNagMs
                    : (lastNag && (now - lastNag) >= repeatNagMs);
                if (nagDue) {
                    flow.set('nag_count', nagCount + 1);
                    flow.set('last_nag_at', now);
                    const elapsedH    = Math.round((now - cycleMs) / 3600000);
                    notificationPayload = {
                        type: 'nag',
                        elapsed_h: elapsedH,
                    };
                }
            }

        } else if (attentionState === 'LIKELY_EMPTY') {
            const likelyEntry = flow.get('likely_empty_entry_time');
            if (likelyEntry && (now - likelyEntry) >= cfg.likely_empty_timeout_h * 3600000) {
                attentionState   = 'NONE';
                attentionTrigger = 'likely_empty_timeout';
                if (cfg.notify_on_likely_empty_timeout) {
                    notificationPayload = { type: 'likely_empty_timeout' };
                }
            }
        }
    }
}

if (attentionState === 'NONE' && contentState === 'CLEAN') {
    contentState   = 'DIRTY';
    contentTrigger = attentionTrigger || 'attention_none';
}

flow.set('operational_state', opState);
flow.set('content_state',     contentState);
flow.set('attention_state',   attentionState);

const statusColors = {
    NONE: 'grey', UNATTENDED: 'yellow', VENTING: 'blue', LIKELY_EMPTY: 'orange'
};

node.status({
    fill:  contentState === 'DIRTY' ? 'grey' : (statusColors[attentionState] || 'yellow'),
    shape: 'dot',
    text:  formatStatus(`${contentState} | ${attentionState}`)
});

const stateSnapshot = {
    contentState,
    attentionState,
    opState,
    cycleFinishedAt: flow.get('cycle_finished_at'),
    lastDoorEventAt: flow.get('last_door_event_at'),
    lastAngleX:      flow.get('last_angle_x')
};

node.send({ target: 'Publish Operational States', payload: stateSnapshot });

if (attentionTrigger || contentTrigger) {
    node.send({
        target: 'Publish Operational Events',
        ts: nowISO,
        attentionChanged: attentionTrigger ? {
            previous_state: prevAttention,
            new_state:      attentionState,
            trigger:        attentionTrigger
        } : null,
        contentChanged: contentTrigger ? {
            previous_state: prevContent,
            new_state:      contentState,
            trigger:        contentTrigger
        } : null
    });
}

if (notificationPayload) {
    node.send({
        target: 'Publish Operational Notifications',
        ts: nowISO,
        notification: notificationPayload
    });
}

return null;

const sm = msg.payload;
const ts = new Date().toISOString();

node.send([{
    topic:   'highland/state/appliance/dishwasher/content',
    payload: JSON.stringify({
        timestamp: ts,
        source:    'dishwasher_attention',
        state:     sm.contentState
    }),
    retain: true
}, null]);

node.send([{
    topic:   'highland/state/appliance/dishwasher/attention',
    payload: JSON.stringify({
        timestamp:          ts,
        source:             'dishwasher_attention',
        state:              sm.attentionState,
        cycle_finished_at:  sm.cycleFinishedAt,
        last_door_event_at: sm.lastDoorEventAt,
        last_angle_x:       sm.lastAngleX
    }),
    retain: true
}, null]);

return [null, msg];

const ts = msg.ts;

if (msg.attentionChanged) {
    node.send([{
        topic:   'highland/event/appliance/dishwasher/attention_changed',
        payload: JSON.stringify({
            timestamp:      ts,
            source:         'dishwasher_attention',
            previous_state: msg.attentionChanged.previous_state,
            new_state:      msg.attentionChanged.new_state,
            trigger:        msg.attentionChanged.trigger
        }),
        retain: false
    }, null]);
}

if (msg.contentChanged) {
    node.send([{
        topic:   'highland/event/appliance/dishwasher/content_changed',
        payload: JSON.stringify({
            timestamp:      ts,
            source:         'dishwasher_attention',
            previous_state: msg.contentChanged.previous_state,
            new_state:      msg.contentChanged.new_state,
            trigger:        msg.contentChanged.trigger
        }),
        retain: false
    }, null]);
}

return [null, msg];

const n   = msg.notification;
const ts  = msg.ts;
const targets = ['people.*.ha_companion'];
const severity = 'low';
let title, message;

switch (n.type) {
    case 'cycle_finished':
        title   = 'Dishwasher finished';
        message = 'Dishes are clean.';
        break;
    case 'nag':
        title   = 'Dishwasher reminder';
        message = `Dishwasher has been done for ${n.elapsed_h} hour${n.elapsed_h !== 1 ? 's' : ''}.`;
        break;
}

if (!title) {
    return [null, msg];
}

return [{
    topic:   'highland/event/notify',
    payload: JSON.stringify({
        timestamp: ts,
        source:    'dishwasher_attention',
        severity,
        title,
        message,
        targets,
        icon: 'mdi:dishwasher'
    }),
    retain: false
}, msg];

const angle_x = msg.payload.angle_x;
if (angle_x === undefined || angle_x === null) return null;

const cfg = global.get('config.device_monitoring')?.appliances?.dishwasher?.attention || {};
const ventThreshold   = cfg.vent_zone_threshold  ?? -5;
const unloadThreshold = cfg.unload_zone_threshold ?? -80;

let zone;
if (angle_x > ventThreshold) {
    zone = 'closed_vent';
} else if (angle_x <= unloadThreshold) {
    zone = 'unload';
} else {
    zone = 'middle';
}

msg.tilt = { angle_x, zone };
return msg;

const device = {
    identifiers: ['highland_dishwasher_attention'],
    name: 'Dishwasher Attention',
    model: 'Attention State Machine',
    manufacturer: 'Highland'
};

node.send({
    topic: 'homeassistant/sensor/highland_dishwasher_attention/content/config',
    payload: JSON.stringify({
        name: 'Dishwasher Content',
        unique_id: 'highland_dishwasher_content',
        state_topic: 'highland/state/appliance/dishwasher/content',
        value_template: '{{ value_json.state }}',
        device
    }),
    retain: true
});

node.send({
    topic: 'homeassistant/sensor/highland_dishwasher_attention/attention/config',
    payload: JSON.stringify({
        name: 'Dishwasher Attention',
        unique_id: 'highland_dishwasher_attention_state',
        state_topic: 'highland/state/appliance/dishwasher/attention',
        value_template: '{{ value_json.state }}',
        device
    }),
    retain: true
});

return null;

const formatStatus = global.get('utils.formatStatus', 'initializers') || (t => t);

const now = Date.now();
const nowISO = new Date(now).toISOString();

const cfg = global.get('config.device_monitoring')?.appliances?.dishwasher?.cycle || {
    start_threshold_w: 2.0,
    idle_baseline_w: 1.0,
    start_duration_s: 5,
    pause_threshold_w: 2.0,
    pause_delay_s: 60,
    expecting_completion_threshold_w: 5.0,
    expecting_completion_delay_s: 300,
    alarm_signal_min_w: 8.0,
    alarm_signal_max_w: 50.0,
    off_delay_s: 1800,
    completion_min_s: 900,
    watchdog_timeout_s: 600
};

let cycleState    = flow.get('cycle_state')       || 'off';
let cycleId       = flow.get('cycle_id')          || null;
let cycleStartMs  = flow.get('cycle_start_ms')    || null;
let energyWh      = flow.get('cycle_energy_wh')   || 0;
let maxPowerW     = flow.get('cycle_max_power_w') || 0;
let lastPowerW    = flow.get('last_power_w')      || 0;
let lastReadingMs = flow.get('last_reading_ms')   || null;
let stateEnterMs  = flow.get('state_enter_ms')    || now;

const type    = msg.event_type;
const power_w = (type === 'power') ? msg.power_w : null;
let cycleEvent = null;

// ─── Energy integration ───────────────────────────────────────────────────
if (type === 'power' && lastReadingMs !== null &&
    !['off', 'finished', 'interrupted', 'force_stopped'].includes(cycleState)) {
    const dt_h = (now - lastReadingMs) / 3_600_000;
    if (dt_h > 0 && dt_h < 0.5) {
        energyWh += (lastPowerW + power_w) / 2 * dt_h;
    }
    if (power_w > maxPowerW) maxPowerW = power_w;
}

// ─── Watchdog (on tick) ───────────────────────────────────────────────────
if (type === 'tick' &&
    ['running', 'between_phases', 'expecting_completion', 'ending'].includes(cycleState)) {
    const lastPowerReadingMs = flow.get('last_power_reading_ms');
    if (lastPowerReadingMs && (now - lastPowerReadingMs) >= cfg.watchdog_timeout_s * 1000) {
        cycleState   = 'force_stopped';
        stateEnterMs = now;
        cycleEvent   = 'force_stopped';
        flow.set('low_power_since_ms', null);
        node.warn('Dishwasher watchdog: sensor silent, forcing stop');
    }
}

// ─── Auto-expire terminal states (on tick) ────────────────────────────────
if (type === 'tick' &&
    ['finished', 'interrupted', 'force_stopped'].includes(cycleState) &&
    cycleEvent === null) {
    if ((now - stateEnterMs) >= cfg.off_delay_s * 1000) {
        cycleState   = 'off';
        stateEnterMs = now;
        cycleId      = null;
        cycleStartMs = null;
        energyWh     = 0;
        maxPowerW    = 0;
    }
}

if (type === 'power' && msg.cold_start &&
    ['running', 'between_phases', 'expecting_completion', 'ending'].includes(cycleState) &&
    power_w <= cfg.idle_baseline_w) {
    // Dishwasher reset during NR downtime — treat as interrupted
    cycleState   = 'interrupted';
    stateEnterMs = now;
    cycleEvent   = 'cycle_interrupted';
}

// ─── Power-driven transitions ─────────────────────────────────────────────
if (type === 'power' && cycleEvent === null) {

    if (cycleState === 'off') {
        if (power_w >= cfg.start_threshold_w) {
            cycleState   = 'starting';
            stateEnterMs = now;
            energyWh     = 0;
            maxPowerW    = power_w;
            const d = new Date(now);
            cycleId = `dw_${d.getFullYear()}${String(d.getMonth()+1).padStart(2,'0')}${String(d.getDate()).padStart(2,'0')}_${String(d.getHours()).padStart(2,'0')}${String(d.getMinutes()).padStart(2,'0')}${String(d.getSeconds()).padStart(2,'0')}`;
            cycleStartMs = now;
        }

    } else if (cycleState === 'starting') {
        if (power_w < cfg.start_threshold_w) {
            // False start
            cycleState   = 'off';
            stateEnterMs = now;
            cycleId      = null;
            cycleStartMs = null;
            energyWh     = 0;
            maxPowerW    = 0;
        } else if ((now - stateEnterMs) >= cfg.start_duration_s * 1000) {
            cycleState   = 'running';
            stateEnterMs = now;
            cycleEvent   = 'cycle_started';
            flow.set('low_power_since_ms', null);
        }

    } else if (cycleState === 'running') {
        if (power_w === 0) {
            // True power-off — board completely dark, not a phase gap
            flow.set('low_power_since_ms', null);
            const zeroSince = flow.get('true_zero_since_ms');
            if (!zeroSince) {
                flow.set('true_zero_since_ms', now);
            } else if ((now - zeroSince) >= cfg.pause_delay_s * 1000) {
                cycleState   = 'interrupted';
                stateEnterMs = now;
                cycleEvent   = 'cycle_interrupted';
                flow.set('true_zero_since_ms', null);
            }
        } else if (power_w < cfg.pause_threshold_w) {
            // Phase gap — control board still alive at 1W
            flow.set('true_zero_since_ms', null);
            const lowSince = flow.get('low_power_since_ms');
            if (!lowSince) {
                flow.set('low_power_since_ms', now);
            } else if ((now - lowSince) >= cfg.pause_delay_s * 1000) {
                cycleState   = 'between_phases';
                stateEnterMs = now;
                flow.set('low_power_since_ms', null);
            }
        } else {
            flow.set('true_zero_since_ms', null);
            flow.set('low_power_since_ms', null);
        }

    } else if (cycleState === 'between_phases') {
        if (power_w >= cfg.pause_threshold_w) {
            cycleState   = 'running';
            stateEnterMs = now;
            flow.set('low_power_since_ms', null);
        }

    } else if (cycleState === 'expecting_completion') {
        if (power_w >= cfg.alarm_signal_min_w && power_w <= cfg.alarm_signal_max_w) {
            // Alarm signal — cycle finished
            cycleState   = 'finished';
            stateEnterMs = now;
            cycleEvent   = 'cycle_finished';
        } else if (power_w > cfg.alarm_signal_max_w) {
            // Another heat cycle resumed
            cycleState   = 'running';
            stateEnterMs = now;
            flow.set('low_power_since_ms', null);
        }

    } else if (cycleState === 'ending') {
        if (power_w >= cfg.start_threshold_w) {
            cycleState   = 'running';
            stateEnterMs = now;
            flow.set('low_power_since_ms', null);
        }
    }

// ─── Tick-driven transitions ──────────────────────────────────────────────
} else if (type === 'tick' && cycleEvent === null) {

    if (cycleState === 'running') {
        // Also check pause via tick in case ZEN15 stopped reporting during low-power period
        const lowSince = flow.get('low_power_since_ms');
        if (lowSince && (now - lowSince) >= cfg.pause_delay_s * 1000) {
            cycleState   = 'between_phases';
            stateEnterMs = now;
            flow.set('low_power_since_ms', null);
        }

    } else if (cycleState === 'between_phases') {
        if ((now - stateEnterMs) >= cfg.expecting_completion_delay_s * 1000) {
            cycleState   = 'expecting_completion';
            stateEnterMs = now;
        }

    } else if (cycleState === 'expecting_completion') {
        if ((now - stateEnterMs) >= cfg.off_delay_s * 1000) {
            // Fallback: alarm never came — use energy gate
            cycleState   = 'ending';
            stateEnterMs = now;
        }

    } else if (cycleState === 'ending') {
        if ((now - stateEnterMs) >= cfg.off_delay_s * 1000) {
            const duration_s = cycleStartMs ? Math.round((now - cycleStartMs) / 1000) : 0;
            if (duration_s >= cfg.completion_min_s) {
                cycleState   = 'finished';
                stateEnterMs = now;
                cycleEvent   = 'cycle_finished';
            } else {
                cycleState   = 'interrupted';
                stateEnterMs = now;
                cycleEvent   = 'cycle_interrupted';
            }
        }
    }
}

// ─── Persist ──────────────────────────────────────────────────────────────
flow.set('cycle_state',       cycleState);
flow.set('cycle_id',          cycleId);
flow.set('cycle_start_ms',    cycleStartMs);
flow.set('cycle_energy_wh',   energyWh);
flow.set('cycle_max_power_w', maxPowerW);
flow.set('state_enter_ms',    stateEnterMs);
if (type === 'power') {
    flow.set('last_power_w',    power_w);
    flow.set('last_reading_ms', now);
}

// ─── Node status ──────────────────────────────────────────────────────────
const statusFill = {
    off: 'grey', starting: 'yellow', running: 'green',
    between_phases: 'yellow', expecting_completion: 'blue',
    ending: 'yellow', finished: 'green',
    interrupted: 'red', force_stopped: 'red'
};
const duration_s = cycleStartMs ? Math.round((now - cycleStartMs) / 1000) : 0;
node.status({
    fill:  statusFill[cycleState] || 'grey',
    shape: 'dot',
    text:  formatStatus(`${cycleState.toUpperCase()} | ${duration_s}s | ${energyWh.toFixed(1)}Wh`)
});

// ─── Dispatch ─────────────────────────────────────────────────────────────
const cycleSnapshot = {
    state:                 cycleState,
    cycle_id:              cycleId,
    cycle_start:           cycleStartMs ? new Date(cycleStartMs).toISOString() : null,
    duration_s:            duration_s,
    energy_wh:             Math.round(energyWh * 100) / 100,
    power_w:               type === 'power' ? power_w : lastPowerW,
    max_power_w:           Math.round(maxPowerW * 100) / 100,
    matched_profile:       null,
    estimated_remaining_s: null
};

node.send({ target: 'Publish Power States', payload: cycleSnapshot });

if (cycleEvent) {
    node.send({
        target:      'Publish Power Events',
        ts:          nowISO,
        cycleEvent:  cycleEvent,
        cycleId:     cycleId,
        cycleStart:  cycleSnapshot.cycle_start,
        duration_s:  duration_s,
        energy_wh:   cycleSnapshot.energy_wh,
        max_power_w: cycleSnapshot.max_power_w
    });
}

return null;

const snapshot = msg.payload;
const ts = new Date().toISOString();

node.send([{
    topic:   'highland/state/appliance/dishwasher/cycle',
    payload: JSON.stringify({
        timestamp:             ts,
        source:                'dishwasher_cycle',
        appliance:             'dishwasher',
        state:                 snapshot.state,
        cycle_id:              snapshot.cycle_id,
        cycle_start:           snapshot.cycle_start,
        duration_s:            snapshot.duration_s,
        energy_wh:             snapshot.energy_wh,
        power_w:               snapshot.power_w,
        max_power_w:           snapshot.max_power_w,
        matched_profile:       snapshot.matched_profile,
        estimated_remaining_s: snapshot.estimated_remaining_s
    }),
    retain: true
}, null]);

return [null, msg];

const ev  = msg.cycleEvent;
const ts  = msg.ts;

// Map force_stopped to cycle_interrupted for downstream consumers
const topic = `highland/event/appliance/dishwasher/${
    ev === 'force_stopped' ? 'cycle_interrupted' : ev
}`;

const payload = {
    timestamp:   ts,
    source:      'dishwasher_cycle',
    appliance:   'dishwasher',
    cycle_id:    msg.cycleId,
    cycle_start: msg.cycleStart,
    duration_s:  msg.duration_s,
    energy_wh:   msg.energy_wh,
    max_power_w: msg.max_power_w,
    status:      ev === 'cycle_finished'   ? 'completed'
               : ev === 'force_stopped'   ? 'force_stopped'
               : ev === 'cycle_interrupted' ? 'interrupted'
               : ev,
    matched_profile: null
};

if (ev === 'force_stopped') {
    payload.termination_reason = 'watchdog';
}

node.send([{
    topic,
    payload: JSON.stringify(payload),
    retain: false
}, null]);

return [null, msg];

const p = msg.payload;
if (typeof p !== 'object' || p === null) return null;

const power_w = p.value;
if (typeof power_w !== 'number') return null;

if (!flow.get('cold_start_done', 'volatile')) {
    flow.set('cold_start_done', true, 'volatile');
    msg.cold_start = true;
}

// Update watchdog timestamp on every received reading
flow.set('last_power_reading_ms', Date.now());

msg.event_type = 'power';
msg.power_w    = power_w;
return msg;
